-- باب هرمي كامل جديد: "فقه المعاملات المالية" (مسار fiqh، مرحلة
-- التأسيس، sort_order 8) — بنفس منهجية سلسلة الأركان الخمسة السابقة
-- (طهارة/صلاة/زكاة/صيام/حج). بطلب المنسِّق: يغطي البيوع، الربا،
-- الإجارة، الرهن، الوكالة، الوقف، الوصية، خيار المجلس.
--
-- تحقُّق تكرار مسبق شامل قبل الكتابة (ILIKE عبر كل learning_items):
-- - "الشفعة" و"بيع الغرر" موجودان بالفعل في bulugh-maram (كورس منفصل) —
--   تجنَّبا كليًا هنا رغم اندراجهما تحت "المعاملات" عموماً.
-- - "ميراث/إرث/مواريث" و"خيار المجلس": صفر تكرار — غير مغطاة.
-- - كل الموضوعات الثمانية المختارة هنا (البيوع، الربا، الإجارة، الرهن،
--   الوكالة، الوقف، الوصية، خيار المجلس) صفر تكرار قبل الإضافة.
--
-- كل استشهاد قرآني حرفي من ملفات public/data/quran/*.json المحلية، وكل
-- حديث تحقَّق حرفياً عبر WebFetch من ar.wikisource.org (صحيح البخاري،
-- سنن ابن ماجه) بنصه ورقمه كما وردا في المصدر.
DO $$
DECLARE
  v_course_id uuid;
  v_unit_id uuid;
BEGIN
  INSERT INTO courses (stage_id, slug, title, description, learning_goal, level, sort_order, pass_percentage, outcomes, status)
  VALUES (
    '9a50da27-e4bc-48a0-ba1f-bf68fa3f3e30',
    'fiqh-muamalat',
    'فقه المعاملات المالية',
    'باب فقهي تأسيسي في أحكام المعاملات المالية بين الناس: أركان البيع وشروطه، تحريم الربا، الإجارة، الرهن، الوكالة، الوقف، الوصية، وخيار المجلس — كل حكم مُسنَد لآية قرآنية أو حديث صحيح موثَّق بنصه ورقمه.',
    'أن يعرف الطالب أركان عقد البيع وشروط صحته، وحرمة الربا وأدلتها، وأحكام الإجارة والرهن والوكالة والوقف والوصية، وخيار المجلس في البيوع.',
    'foundational',
    8,
    70,
    '["معرفة أركان البيع وشروطه", "معرفة تحريم الربا وأدلته", "معرفة أحكام الإجارة والرهن", "معرفة الوكالة والوقف والوصية", "معرفة خيار المجلس في البيوع"]'::jsonb,
    'published'
  )
  RETURNING id INTO v_course_id;

  INSERT INTO course_units (course_id, title, sort_order)
  VALUES (v_course_id, 'الدروس', 1)
  RETURNING id INTO v_unit_id;

  INSERT INTO learning_items (unit_id, item_type, title, description, session_estimate, weight, sort_order, status, is_approved)
  VALUES
  (v_unit_id, 'lesson', 'أركان البيع وشروطه',
   'البيع: مبادلة مال بمال على وجه التراضي، وأصل مشروعيته الرضا التام بين المتعاقدين لا الإكراه أو الخديعة. قال الله تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُم بَيْنَكُم بِالْبَاطِلِ إِلَّا أَن تَكُونَ تِجَارَةً عَن تَرَاضٍ مِّنكُمْ﴾ (النساء: 29). لعقد البيع عند الفقهاء أركان ثلاثة: العاقدان (البائع والمشتري، ويُشترط فيهما الأهلية)، والصيغة (الإيجاب والقبول الدالان على الرضا)، والمعقود عليه (السلعة والثمن، ويُشترط فيهما أن يكونا مملوكين معلومين مقدور على تسليمهما). فإذا اختل ركن أو شرط من هذه الأركان بطل العقد أو فسد بحسب موضع الخلل.',
   1.0, 12.50, 1, 'published', true),
  (v_unit_id, 'lesson', 'تحريم الربا',
   'الربا: الزيادة المشروطة في أحد عوضي المبادلة (كالمال بالمال) دون مقابل حقيقي، وهو من أعظم المحرمات في المعاملات المالية. قال الله تعالى: ﴿الَّذِينَ يَأْكُلُونَ الرِّبَا لَا يَقُومُونَ إِلَّا كَمَا يَقُومُ الَّذِي يَتَخَبَّطُهُ الشَّيْطَانُ مِنَ الْمَسِّ ذَٰلِكَ بِأَنَّهُمْ قَالُوا إِنَّمَا الْبَيْعُ مِثْلُ الرِّبَا وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا﴾ (البقرة: 275)، وقال سبحانه في تحذير شديد: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَذَرُوا مَا بَقِيَ مِنَ الرِّبَا إِن كُنتُم مُّؤْمِنِينَ * فَإِن لَّمْ تَفْعَلُوا فَأْذَنُوا بِحَرْبٍ مِّنَ اللَّهِ وَرَسُولِهِ﴾ (البقرة: 278-279)، وهو التهديد الوحيد في القرآن بـ"حرب من الله ورسوله" على معصية بعينها، مما يدل على عِظَم خطر الربا وأثره المُفسِد على المجتمع الاقتصادي.',
   1.0, 12.50, 2, 'published', true),
  (v_unit_id, 'lesson', 'الإجارة',
   'الإجارة: عقد على منفعة مباحة معلومة بعوض معلوم، سواء كانت المنفعة عملاً (كإجارة الأجير) أو منفعة عين (كإجارة دار أو أرض). عن عبد الله بن عمر رضي الله عنهما، قال رسول الله ﷺ: «أعطوا الأجير أجره قبل أن يجف عرقه» — رواه ابن ماجه، كتاب الرهون، باب أجر الأجراء (حديث 2537). يدل الحديث على وجوب المبادرة بدفع أجرة الأجير فور انتهاء عمله دون مماطلة، وعدم جواز تأخير حقه بلا عذر مقبول، وهو أصل عظيم في حفظ حقوق العمال والأُجراء.',
   1.0, 12.50, 3, 'published', true),
  (v_unit_id, 'lesson', 'الرهن',
   'الرهن: توثيق دَين بعين مالية يجوز بيعها، تُحبَس عند الدائن أو من يتفقان عليه ضماناً لاستيفاء الدين عند حلوله. قال الله تعالى: ﴿وَإِن كُنتُمْ عَلَىٰ سَفَرٍ وَلَمْ تَجِدُوا كَاتِبًا فَرِهَانٌ مَّقْبُوضَةٌ فَإِنْ أَمِنَ بَعْضُكُم بَعْضًا فَلْيُؤَدِّ الَّذِي اؤْتُمِنَ أَمَانَتَهُ وَلْيَتَّقِ اللَّهَ رَبَّهُ﴾ (البقرة: 283). خصَّت الآية حالة السفر وتعذُّر الكتابة بذكر الرهن، لكن جمهور الفقهاء على جواز الرهن في الحضر أيضاً قياساً وبدلالة فعل النبي ﷺ نفسه (رهن درعه عند يهودي في المدينة مقابل طعام اشتراه منه، كما في الصحيحين)، وذكر السفر في الآية خرج مخرج الغالب لا التخصيص.',
   1.0, 12.50, 4, 'published', true),
  (v_unit_id, 'lesson', 'الوكالة',
   'الوكالة: تفويض شخص لآخر للتصرف عنه في أمر جائز، كشراء سلعة أو بيعها أو استيفاء حق. من أدلة مشروعيتها في القرآن قصة أصحاب الكهف حين اتفقوا على إرسال أحدهم وكيلاً عنهم لشراء الطعام: ﴿فَابْعَثُوا أَحَدَكُم بِوَرِقِكُمْ هَٰذِهِ إِلَى الْمَدِينَةِ فَلْيَنظُرْ أَيُّهَا أَزْكَىٰ طَعَامًا فَلْيَأْتِكُم بِرِزْقٍ مِّنْهُ﴾ (الكهف: 19)، ففوَّضوه في اختيار الطعام الأطيب وشرائه لهم، وهو مثال قرآني صريح على جواز التوكيل في المعاملات المالية. من شروط صحة الوكالة أن يكون التصرف المُوكَّل فيه جائزاً شرعاً، وأن يكون الوكيل أهلاً للتصرف الذي وُكِّل فيه.',
   1.0, 12.50, 5, 'published', true),
  (v_unit_id, 'lesson', 'الوقف',
   'الوقف: حبس أصل المال (كالأرض أو الدار) عن التصرف بالبيع أو الهبة أو الإرث، وتسبيل منفعته في وجه من وجوه البر بصفة مستمرة. عن ابن عمر رضي الله عنهما: أن عمر بن الخطاب أصاب أرضاً بخيبر، فأتى النبي ﷺ يستأمره فيها، فقال: يا رسول الله، إني أصبت أرضاً بخيبر لم أُصب مالاً قط أنفس عندي منه، فما تأمرني به؟ قال: «إن شئت حبَّست أصلها وتصدَّقت بها» — رواه البخاري، كتاب الوصايا (حديث 2620). فتصدَّق بها عمر رضي الله عنه على أن لا يُباع أصلها ولا يُوهب ولا يُورَث، وجعل ريعها للفقراء وذوي القربى وفي سبيل الله. هذا الحديث هو الأصل الأول الذي بُني عليه فقه الوقف الإسلامي.',
   1.0, 12.50, 6, 'published', true),
  (v_unit_id, 'lesson', 'الوصية',
   'الوصية: تصرف في الثلث فأقل من المال يُنفَّذ بعد الموت، لغير الوارث. قال الله تعالى في أصل مشروعيتها: ﴿كُتِبَ عَلَيْكُمْ إِذَا حَضَرَ أَحَدَكُمُ الْمَوْتُ إِن تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ بِالْمَعْرُوفِ حَقًّا عَلَى الْمُتَّقِينَ﴾ (البقرة: 180) — وهذا الحكم بالوصية الواجبة للوالدين والأقربين نُسِخ فيما يخص الورثة منهم بآيات المواريث المُفصَّلة اللاحقة (سورة النساء)، فأصبحت الوصية لهم غير واجبة (بل لا تصح لوارث إلا بإجازة بقية الورثة عند الجمهور)، وبقي حكمها ثابتاً فيمن لا يرث كالأقارب غير الوارثين والفقراء. وعن عبد الله بن عمر رضي الله عنهما، قال رسول الله ﷺ: «ما حقُّ امرئ مسلم له شيء يوصي فيه يبيت ليلتين إلا ووصيته مكتوبة عنده» — رواه البخاري، كتاب الوصايا (حديث 2587)، حثاً على المبادرة بكتابة الوصية وعدم تأخيرها.',
   1.0, 12.50, 7, 'published', true),
  (v_unit_id, 'lesson', 'خيار المجلس',
   'خيار المجلس: حق كل من المتبايعين في فسخ عقد البيع أو إمضائه ما داما في مجلس العقد لم يتفرقا بأبدانهما، وهو من مكارم الفقه الإسلامي في إعطاء العاقدين فرصة أخيرة لمراجعة قرارهما. عن عبد الله بن عمر رضي الله عنهما، قال رسول الله ﷺ: «البيعان بالخيار ما لم يتفرقا، فإن صدقا وبيَّنا بورك لهما في بيعهما، وإن كذبا وكتما محقت بركة بيعهما» — رواه البخاري، كتاب البيوع (حديث 2004). ربط الحديث بين استمرار خيار الفسخ وبين الصدق في وصف السلعة، فجعل الصدق والبيان سبباً للبركة، والكذب والكتمان سبباً لمحقها، وهو ترغيب أخلاقي مباشر يقترن بالحكم الفقهي.',
   1.0, 12.50, 8, 'published', true);

  UPDATE learning_paths lp SET total_sessions = (
    SELECT sum(li.session_estimate)::int
    FROM path_stages ps JOIN courses c ON c.stage_id = ps.id
    JOIN course_units cu ON cu.course_id = c.id
    JOIN learning_items li ON li.unit_id = cu.id
    WHERE ps.path_id = lp.id
  ), updated_at = now() WHERE lp.slug = 'fiqh';
END $$;
